from typing import Optional

# class TreeNode:
#     def __init__(self, val=0, left=None, right=None):
#         self.val = val
#         self.left = left
#         self.right = right

def longestConsecutive(root: Optional['TreeNode']) -> int:
    if root is None:
        return 0

    def dfs(node: Optional['TreeNode'], length: int, prev: int) -> int:
        if node is None:
            return length - 1
        curr_length = length if node.val == prev + 1 else 1
        left = dfs(node.left, curr_length + 1, node.val)
        right = dfs(node.right, curr_length + 1, node.val)
        return max(curr_length, left, right)

    return dfs(root, 1, root.val)
